        this.mantissa = pb.add(this.mantissa, pb.div(this.pack.y, 128.0));
        this.mantissa = pb.add(this.mantissa, pb.div(this.pack.z, 32768.0));
        this.mantissa = pb.add(this.mantissa, pb.div(this.pack.w, 8388608.0));
