            this._offsetsAndWeights[i * 4] = this._uvStep.x * i;
            this._offsetsAndWeights[i * 4 + 1] = this._uvStep.y * i;
            this._offsetsAndWeights[i * 4 + 2] = kernel[this.kernelRadius - i] / sum;
