        this._numEmitCount = 0;
        this._scalar = 1;
        this._airResistence = false;
        this._startTick = 0;
        this._delay = 0;
        this._particleRotationMin = 0;
        this._particleRotationMax = 0;
        this._jitterSpeed = 1;
