class JSONProp {
    parent;
    name;
    constructor(data){
        this.parent = data;
        if (this.parent && !(this.parent instanceof JSONArray)) {
            for(let i = 1;; i++){
                const name = `field${i}`;
                if (!this.parent.value.find((p)=>p?.name === name)) {
                    this.name = name;
                    break;
                }
            }
        } else {
            this.name = '';
        }
    }
}
class JSONString extends JSONProp {
    value;
    constructor(data, value = ''){
        super(data);
        this.value = value;
    }
}
class JSONNumber extends JSONProp {
    value;
    constructor(data, value = 0){
        super(data);
        this.value = value;
    }
}
class JSONBool extends JSONProp {
    value;
    constructor(data, value = false){
        super(data);
        this.value = value;
    }
}
class JSONData extends JSONProp {
    value;
    data;
    isnull;
    isundefined;
    constructor(parent, data = {}){
        super(parent);
        this.updateObject(data);
    }
    updateObject(data) {
        this.value = [];
        this.data = data;
        this.isnull = this.data === null;
        if (this.data) {
            this.parseObject();
        }
    }
    parseObject() {
        for (const key of Object.keys(this.data)){
            const val = this.data[key];
            let prop;
            if (typeof val === 'string') {
                prop = new JSONString(this, val);
            } else if (typeof val === 'number') {
                prop = new JSONNumber(this, val);
            } else if (typeof val === 'boolean') {
                prop = new JSONBool(this, val);
            } else if (typeof val === 'object') {
                prop = Array.isArray(val) ? new JSONArray(this, val) : new JSONData(this, val);
            } else {
                continue;
            }
            prop.name = key;
            this.value.push(prop);
        }
    }
    updateProps() {
        for (const key of Object.keys(this.data)){
            if (!this.value.find((p)=>p?.name === key)) {
                delete this.data[key];
            }
        }
        for (const prop of this.value){
            if (prop instanceof JSONData) {
                this.data[prop.name] = prop.data;
            } else if (prop) {
                this.data[prop.name] = prop.value;
            }
        }
        return this.data;
    }
}
class JSONArray extends JSONData {
    constructor(parent, data = []){
        super(parent);
        this.updateObject(data);
    }
    updateObject(data) {
        this.value = [];
        this.data = data;
        this.isnull = this.data === null;
        if (this.data) {
            this.parseObject();
        }
    }
    parseObject() {
        const data = this.data;
        if (data?.length > 0) {
            for(let i = 0; i < data.length; i++){
                const val = data[i];
                let prop;
                if (typeof val === 'string') {
                    prop = new JSONString(this, val);
                } else if (typeof val === 'number') {
                    prop = new JSONNumber(this, val);
                } else if (typeof val === 'boolean') {
                    prop = new JSONBool(this, val);
                } else if (typeof val === 'object') {
                    prop = !val ? null : Array.isArray(val) ? new JSONArray(this, val) : new JSONData(this, val);
                } else {
                    continue;
                }
                this.value.push(prop);
            }
        }
    }
    updateProps() {
        const data = this.data;
        data.splice(0, data.length);
        for(let i = 0; i < this.value.length; i++){
            const prop = this.value[i];
            if (prop instanceof JSONArray) {
                this.data[i] = prop.data;
            } else if (prop instanceof JSONData) {
                this.data[i] = prop.data;
            } else {
                this.data[i] = prop?.value ?? null;
            }
        }
        return this.data;
    }
}
