            const sampler = gltf.samplers && gltf.samplers[samplerIndex];
            if (sampler) {
                switch(sampler.wrapS){
                    case 0x2901:
                        wrapS = 'repeat';
                        break;
                    case 0x8370:
                        wrapS = 'mirrored-repeat';
                        break;
                    case 0x812f:
                        wrapS = 'clamp';
                        break;
                }
                switch(sampler.wrapT){
                    case 0x2901:
                        wrapT = 'repeat';
                        break;
                    case 0x8370:
                        wrapT = 'mirrored-repeat';
                        break;
                    case 0x812f:
                        wrapT = 'clamp';
                        break;
                }
                switch(sampler.magFilter){
                    case 0x2600:
                        magFilter = 'nearest';
                        break;
                    case 0x2601:
                        magFilter = 'linear';
                        break;
                }
                switch(sampler.minFilter){
                    case 0x2600:
                        minFilter = 'nearest';
                        mipFilter = 'none';
                        break;
                    case 0x2601:
                        minFilter = 'linear';
                        mipFilter = 'none';
                        break;
                    case 0x2700:
                        minFilter = 'nearest';
                        mipFilter = 'nearest';
                        break;
                    case 0x2701:
                        minFilter = 'linear';
                        mipFilter = 'nearest';
                        break;
                    case 0x2702:
                        minFilter = 'nearest';
                        mipFilter = 'linear';
                        break;
                    case 0x2703:
                        minFilter = 'linear';
                        mipFilter = 'linear';
                        break;
                }
            }
            const imageIndex = textureInfo.source;
            const hash = `${imageIndex}:${!!sRGB}:${wrapS}:${wrapT}:${minFilter}:${magFilter}:${mipFilter}`;
